INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (1, 1, "だからわたし、\n勇気を出して言ってみたんです！\nお友だちになりませんか、って。", 0, 10, 0, 0, 11, 72021, 1, 72);
INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES ("", 0, "", "", 0, "", "", 91, 72022, 0, 72);
