INSERT INTO `v1_d209f75f973f81be26650d3364df60224f8959a608c699a134dced73946a32db` VALUES (1, 1, "……でも。\n今回の冒険で、夢見ることは\n大きな力だと知りましたから。", 0, 10, 0, 0, 11, 142024, 1, 142);
